import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        if (userInput.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        // Safely copy input to buffer
        char[] buffer = new char[10];
        userInput.getChars(0, Math.min(userInput.length(), 10), buffer, 0);

        System.out.println("Input stored successfully in buffer.");
    }
}

### Explanation:
취약유형: Buffer Overflow
